const item = $input.first().json;
const dadosConversa = typeof item.dados_conversa === 'string' ? JSON.parse(item.dados_conversa || '{}') : (item.dados_conversa || {});
const flags = typeof item.flags === 'string' ? JSON.parse(item.flags || '[]') : (item.flags || []);

const prompt = `Você é um especialista em análise de risco financeiro e inadimplência. Analise os dados da conversa comercial abaixo e avalie o risco de crédito e inadimplência deste cliente.

Dados da conversa:
- Resultado: ${item.resultado || 'não definido'}
- Flags detectadas: ${JSON.stringify(flags)}
- Dados da conversa: ${JSON.stringify(dadosConversa)}
- Data: ${item.created_at}

Retorne APENAS um JSON válido com a seguinte estrutura:
{
  "nivel_risco": "baixo|medio|alto|critico",
  "sinais_detectados": [
    "sinal 1 de risco identificado",
    "sinal 2 de risco identificado"
  ],
  "probabilidade_inadimplencia": 0.35,
  "acoes_recomendadas": [
    "ação 1 recomendada",
    "ação 2 recomendada"
  ],
  "historico_pagamentos_resumo": {
    "observacoes": "observações sobre padrão de pagamento inferido",
    "risco_concentracao": false
  }
}

A probabilidade_inadimplencia deve ser um número entre 0.0 e 1.0. Não inclua markdown, apenas o JSON puro.`;

return [{
  json: {
    ...item,
    prompt
  }
}];

const response = $input.first().json;
const content = response.content?.[0]?.text || '{}';
let parsed;
try { parsed = JSON.parse(content); } catch(e) { parsed = {erro: 'parse_failed', raw: content}; }
return [{json: {...$input.first().json, resultado: parsed}}];
